        const isEditing = editingCell === label;
        const isRemoteEditing = remoteEditingCells.has(label);
        const displayValue = getDisplayValue(label);

        return (
          <div
            key={label}
            role="gridcell"
            data-cell={label}
            data-remote-editing={isRemoteEditing ? "true" : "false"}
            onClick={() => !isEditing && handleCellClick(label)}
            style={{
              border: isRemoteEditing ? "2px solid orange" : "1px solid #ccc",
              padding: "4px 6px",
              boxSizing: "border-box",
              fontFamily: "monospace",
            }}
          >
            {isEditing ? (
              <input
                autoFocus
                value={editValue}
                onChange={(e) => setEditValue(e.target.value)}
                onBlur={handleBlur}
                onKeyDown={handleKeyDown}
                style={{
                  width: "100%",
                  border: "none",
                  outline: "none",
                  fontFamily: "monospace",
                  fontSize: "inherit",
                }}
              />
            ) : (
              displayValue
            )}
          </div>
        );
      })}
    </div>
  );
}

