                  outline: "none",
                  fontFamily: "monospace",
                  fontSize: "inherit",
                  background: "transparent",
                  padding: 0,
                  margin: 0,
                }}
              />
            ) : (
              displayValue
            )}
          </div>
        );
      })}
    </div>
  );
}

function GridFallback() {
  return (
    <div
      role="grid"
      style={{
        display: "grid",
        gridTemplateColumns: "repeat(5, 80px)",
        gridAutoRows: "32px",
        gap: 0,
      }}
    >
      {CELL_LABELS.map((label) => (
        <div
          key={label}
          role="gridcell"
          data-cell={label}
          data-remote-editing="false"
          style={{
            border: "1px solid #ccc",
            padding: "4px 6px",
            boxSizing: "border-box",
            fontFamily: "monospace",
          }}
        />
      ))}
    </div>
  );
}

export default function Page() {
  const roomId = `spreadsheet-${process.env.NEXT_PUBLIC_ZEALT_RUN_ID}`;
  const publicKey = process.env.NEXT_PUBLIC_LIVEBLOCKS_PUBLIC_KEY!;

  return (
    <LiveblocksProvider publicApiKey={publicKey}>
      <RoomProvider
        id={roomId}
        initialStorage={{ cells: new LiveMap() }}
        initialPresence={{ editingCell: null }}
      >
        <ClientSideSuspense fallback={<GridFallback />}>
          {() => <Spreadsheet />}
        </ClientSideSuspense>
      </RoomProvider>
    </LiveblocksProvider>
  );
}

